sql:
SELECT result_id, horse_id, prize_money, time
FROM race_results
WHERE prize_money > 100000.0;

SELECT horses.horse_name, trainers.trainer_name
FROM horses
INNER JOIN trainers ON horses.trainer_id = trainers.trainer_id;

SELECT *
FROM jockeys
ORDER BY jockey_experience DESC;

SELECT jockey_name, jockey_nationality, jockey_date_of_birth, jockey_weight, jockey_height, jockey_experience
FROM jockeys
WHERE jockey_id > 0;

SELECT h.horse_name, t.trainer_name
FROM horses h
INNER JOIN trainers t ON h.trainer_id = t.trainer_id;

SELECT jockey_name, jockey_experience
FROM jockeys
WHERE jockey_id = 1;

SELECT jockey_name || ',' || jockey_experience AS jockey_info
FROM jockeys
WHERE jockey_id = 0;

SELECT horses.horse_name, owners.owner_name
FROM horses
JOIN owners ON horses.horse_owner_id = owners.owner_id;

external_knowledge:
- Seasoned jockeys refer to those with over 5 years of experience;
- A significant monetary mark is considered to be over $50,000 in average earnings;
- Converting prize money to radians and calculating the hyperbolic tangent of such values are mathematical transformations for data analysis purposes.

sql:
SELECT h.horse_name, o.owner_name
FROM horses h
INNER JOIN owners o ON h.horse_owner_id = o.owner_id;

external_knowledge:
- "caretakers" refers to trainers;
- "sires" metaphorically refers to owners;
- "riders that hail from the emerald isle" refers to jockeys whose nationality is 'Ireland'.

sql:
SELECT COUNT(*) as Total_Male_Horses
FROM horses
WHERE horse_gender = 'M';

external_knowledge:
- 'waves of competition' and 'fields where they raced' refer to the races and tracks;
- 'noble steeds' and 'their victories and challenges' correspond to the horses and their race results;
- 'proud trainers', 'skilled riders', and 'mighty owners' relate to the trainers, jockeys, and owners;
- 'tides of time' and 'laurels of victory' refer to the order by race date and result position.
